// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.LmdbStore;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/** Regression tests for scoped groups and post-query VALUES in the LMDB native query engine. */
public class LmdbNativeScopeAndValuesRegressionTest {

	private static final String EX = "http://example.org/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc").setSketchEstimatorEnabled(false);
		repository = new SailRepository(new LmdbStore(dataDir, config));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			conn.add(vf.createIRI(EX, "s4"), vf.createIRI(EX, "p"), vf.createLiteral(4));
			conn.add(vf.createIRI(EX, "a"), vf.createIRI(EX, "name"), vf.createLiteral("Alan"));
			conn.add(vf.createIRI(EX, "a"), vf.createIRI(EX, "email"), vf.createLiteral("alan@example.org"));
			conn.add(vf.createIRI(EX, "numeric"), vf.createIRI(EX, "numericValue"),
					vf.createLiteral("01", XSD.INTEGER));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	@Test
	public void nestedGroupFilterDoesNotSeeOuterBind() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "SELECT ?s ?v ?z WHERE {\n"
				+ "  BIND(4 AS ?z)\n"
				+ "  { ?s :p ?v . FILTER(?v = ?z) }\n"
				+ "}";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).isEmpty();
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("a native root must not flatten a nested variable-scope boundary")
				.isEqualTo(compiledBefore);
	}

	@Test
	public void postQueryValuesWithTwoStringBindingsJoinsStoredTerms() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "SELECT ?s ?o1 ?o2 WHERE {\n"
				+ "  ?s ?p1 ?o1 .\n"
				+ "  ?s ?p2 ?o2 .\n"
				+ "} VALUES (?o1 ?o2) {\n"
				+ "  (\"Alan\" \"alan@example.org\")\n"
				+ "}";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).singleElement().satisfies(bindings -> {
				assertThat(bindings.getValue("s")).isEqualTo(conn.getValueFactory().createIRI(EX, "a"));
				assertThat(bindings.getValue("o1")).isEqualTo(conn.getValueFactory().createLiteral("Alan"));
				assertThat(bindings.getValue("o2"))
						.isEqualTo(conn.getValueFactory().createLiteral("alan@example.org"));
			});
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("string-valued post-query VALUES should stay on the native row path")
				.isGreaterThan(compiledBefore);
	}

	@Test
	public void postQueryValuesStillUsesRdfTermIdentityForNumericLiterals() {
		String query = "PREFIX : <" + EX + ">\n"
				+ "PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>\n"
				+ "SELECT ?s WHERE { ?s :numericValue ?value }\n"
				+ "VALUES ?value { \"1\"^^xsd:integer }";

		long compiledBefore = LmdbNativeAggregateCompiler.COMPILED.get();
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).isEmpty();
		}
		assertThat(LmdbNativeAggregateCompiler.COMPILED.get())
				.as("numeric term identity is unsafe for the native raw-id VALUES path")
				.isEqualTo(compiledBefore);
	}
}
